column.value:
{
  "pageDescription": "Sample Intake / Sample Creation",
  "dataPoints": {
    "sampleIdentity": {
      "sampleId": {"type": "text", "label": "Sample ID / Registration name", "example": "Ach-21-FY004", "required": true},
      "sampleSource": {"type": "choice", "label": "Sample Source", "options": ["Field", "External organization (UOG, WHO, other country)"], "required": true},
      "projectName": {"type": "text", "label": "Project Name", "required": true}
    },
    "sampleType": {
      "type": "reference",
      "label": "Sample Type",
      "source": "type_of_sample",
      "options": ["Whole blood", "Serum", "Plasma", "DBS", "Cell pellet", "Biopsy / microbiopsy", "Mosquito / sandfly / tsetsefly", "Tissue", "Culture", "DNA/RNA preservative"],
      "required": true
    },
    "collectionMetadata": {
      "collectionSite": {"type": "text", "label": "Collection site/location", "required": true},
      "collectionDateTime": {"type": "dateTime", "label": "Collection date & time", "required": true},
      "collectedBy": {"type": "text", "label": "Collected by (person / organization)", "required": true},
      "numberOfSamples": {"type": "integer", "label": "Number of samples", "example": "10 tubes, 2 boxes", "required": true}
    }
  },
  "systemActions": ["Generate unique system ID", "Generate label / barcode", "Set status: Registered - Awaiting Reception"],
  "csvColumnMapping": {
    "groupIdColumn": "sample_id",
    "sampleTypeColumn": "sample_type",
    "numOfSamplesColumn": "num_of_samples",
    "additionalColumns": ["sample_source", "project_name", "collection_site", "collection_date_time", "collected_by"]
  },
  "nextPage": "Laboratory Reception & Verification"
}

{
  "pageDescription": "Laboratory Reception & Verification",
  "dataPoints": {
    "receiptInformation": {
      "receivedDateTime": {"type": "dateTime", "label": "Received date & time", "required": true},
      "receivedBy": {"type": "text", "label": "Received by (staff name)", "required": true},
      "conditionOnArrival": {"type": "text", "label": "Condition on arrival", "required": false}
    },
    "verification": {
      "sampleMatchesRegistration": {"type": "boolean", "label": "Sample matches registration", "options": ["Yes", "No"], "required": true},
      "labelVerified": {"type": "boolean", "label": "Label verified", "options": ["Yes", "No"], "required": true}
    },
    "qualityAssessment": {
      "qcResult": {"type": "choice", "label": "QC Result", "options": ["Pass", "Fail", "Pass with remarks"], "required": true},
      "qcRemarks": {"type": "text", "label": "QC Remarks", "conditionalOn": "qcResult != Pass", "required": false}
    },
    "decisions": {
      "failAction": {"type": "choice", "label": "Action if Fail", "options": ["Notify researcher", "Discarded", "Proceed with remarks"], "conditionalOn": "qcResult == Fail", "required": false},
      "passAction": {"type": "choice", "label": "Action if Pass", "options": ["Proceed to storage"], "conditionalOn": "qcResult == Pass || qcResult == Pass with remarks", "required": false}
    }
  },
  "systemActions": ["Update sample status: Received - QC Passed", "Update sample status: Received - QC Failed"],
  "bulkOperations": {
    "enabled": true,
    "applyToSelected": ["receivedDateTime", "receivedBy", "qcResult"]
  },
  "nextPage": "Temporary Storage"
}

{
  "pageDescription": "Temporary Storage Assignment",
  "dataPoints": {
    "storageHierarchy": {
      "room": {"type": "reference", "label": "Room", "source": "storage_room", "required": true},
      "freezer": {"type": "reference", "label": "Freezer / Device", "source": "storage_device", "required": true},
      "storageType": {"type": "choice", "label": "Storage Type", "options": ["Raw", "Processed"], "required": false},
      "rack": {"type": "reference", "label": "Rack", "source": "storage_rack", "required": true},
      "box": {"type": "reference", "label": "Box", "source": "storage_box", "required": true},
      "wellPosition": {"type": "wellGrid", "label": "Well / Position", "rows": 8, "columns": 12, "required": true}
    },
    "assignmentMetadata": {
      "assignedBy": {"type": "text", "label": "Assigned By", "required": true},
      "assignedDateTime": {"type": "dateTime", "label": "Assigned Date/Time", "required": true}
    },
    "environmentalMonitoring": {
      "freezerId": {"type": "text", "label": "Freezer ID", "required": true},
      "temperatureCheckTime": {"type": "choice", "label": "Temperature Check", "options": ["AM", "PM"], "required": true},
      "temperatureValue": {"type": "number", "label": "Temperature Value", "unit": "°C", "required": true},
      "checkedBy": {"type": "text", "label": "Checked By", "required": true}
    }
  },
  "systemActions": ["Update sample status: Stored - Temporary Storage", "Log temperature monitoring data"],
  "bulkOperations": {
    "enabled": true,
    "applyToSelected": ["room", "freezer", "storageType", "rack", "box"]
  },
  "nextPage": "Sample Processing"
}

{
  "pageDescription": "Sample Processing Preparation",
  "dataPoints": {
    "processingDetails": {
      "processingType": {"type": "choice", "label": "Processing Type", "options": ["Aliquoting", "DBS punching", "Extraction", "Culture"], "required": true},
      "technicianName": {"type": "text", "label": "Technician Name", "required": true},
      "processingDate": {"type": "date", "label": "Processing Date", "required": true}
    },
    "sampleReview": {
      "missedSamples": {"type": "action", "label": "Register Missed Samples", "description": "Register additional samples missed from field"},
      "parentSampleSelection": {"type": "reference", "label": "Parent Sample", "source": "sample_item", "required": false}
    },
    "reagentInstrumentSelection": {
      "reagents": {"type": "multiSelect", "label": "Reagents", "source": "reagent_inventory", "required": false},
      "instruments": {"type": "multiSelect", "label": "Instruments", "source": "instrument_inventory", "required": false},
      "batchNumber": {"type": "text", "label": "Batch Number", "required": false},
      "lotNumber": {"type": "text", "label": "Lot Number", "required": false}
    }
  },
  "systemActions": ["Lock parent sample for processing", "Link reagents to process", "Link instruments to process"],
  "bulkOperations": {
    "enabled": true,
    "applyToSelected": ["processingType", "technicianName", "processingDate", "reagents", "instruments"]
  },
  "nextPage": "Aliquoting / Bulk Import"
}
